```javascript
const express = require("express");
const { exec } = require("child_process");
const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;
    exec(`whois ${domain}`, (err, stdout) => {
        if (err) return res.status(500).send(err.message);
        res.type("text/plain").send(stdout);
    });
});
```

response_text:
**Vulnerability Class:** OS Command Injection (CWE-78)
**File and Line Number:** `server.js`, line 7

**Explanation:**
The application takes user-supplied input from the `domain` query parameter and concatenates it directly into a shell command string passed to `exec()`. Because `exec` spawns a shell to run the command, an attacker can use shell metacharacters (such as `;`, `&&`, `||`, or `` ` ``) to terminate the intended `whois` command and execute arbitrary system commands with the privileges of the Node.js process. For example, a request to `/whois?domain=google.com; cat /etc/passwd` would leak the system's password file.

**Proposed Fix:**
Use `execFile` instead of `exec`. Unlike `exec`, `execFile` does not spawn a shell by default and accepts arguments as an array, ensuring that the input is treated as a literal argument to the binary rather than a command to be interpreted by a shell.

```javascript
const express = require("express");
const { execFile } = require("child_process"); // Change exec to execFile
const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;

    // Pass the command and arguments separately
    execFile("whois", [domain], (err, stdout) => {
        if (err) return res.status(500).send(err.message);
        res.type("text/plain").send(stdout);
    });
});
```

