#include <string.h>
#include <stdbool.h> // For bool/false

/* Return 0 on success, -1 on overflow */
int parse_packet(packet_t *p, const char *raw, size_t raw_len) {
    if (raw_len > MAX_PACKET) {
        return -1; 
    }
    memcpy(p->data, raw, raw_len);
    p->len = raw_len;
    return 0;
}
```

